        if (offset0 < total_elements) output[offset0] = sum;

        sum += val1;
        if (offset1 < total_elements) output[offset1] = sum;

        sum += val2;
        if (offset2 < total_elements) output[offset2] = sum;

        sum += val3;
        if (offset3 < total_elements) output[offset3] = sum;
    }

    // Handle remaining elements
    for (; dim_idx >= 0; --dim_idx) {
        const int64_t offset = base_offset + dim_idx * inner_size;

        // Validate offset before accessing memory
